function useAsyncData<T>(loader: () => Promise<T>, deps: ReadonlyArray<unknown>) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>("");
  const [nonce, setNonce] = useState(0);

  useEffect(() => {
    let cancelled = false;
    loader()
      .then((d) => {
        if (cancelled) return;
        setData(d);
      })
      .catch((err) => {
        if (cancelled) return;
        setError(err instanceof Error ? err.message : String(err));
      })
      .finally(() => {
        if (cancelled) return;
        setLoading(false);
      });
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [...deps, nonce]);

  return {
    data,
    loading,
    error,
    reload: () => {
      setLoading(true);
      setError("");
      setNonce((n) => n + 1);
    },
  };
}

async function fetchAllSoldManufactured() {
  const pageSize = 100;
  const rows: Manufactured[] = [];
  let page = 1;
  let totalPages = 1;

  do {
    const response = await listManufactured({ status: "Sold", page, limit: pageSize });
    rows.push(...response.data);
    totalPages = Math.max(1, Math.ceil(response.total / response.limit));
    page += 1;
  } while (page <= totalPages);

  return rows;
}

async function fetchAllSales() {
  const pageSize = 100;
  const rows: Sale[] = [];
  let page = 1;
  let totalPages = 1;

  do {
    const response = await listSales({ page, limit: pageSize });
    rows.push(...response.data);
    totalPages = Math.max(1, Math.ceil(response.total / response.limit));
    page += 1;
  } while (page <= totalPages);

  return rows;
}

function formatNumber(n: number) {
  return n.toLocaleString("en-IN");
}

function formatDateOnly(value: string | Date | undefined) {
  if (!value) return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toISOString().slice(0, 10);
}

function formatDateTimeLocal(value: string | Date | undefined) {
  if (!value) return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  const pad = (n: number) => String(n).padStart(2, "0");
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

