function serviceStagesForPermissions(permissions: string[], role?: string): ServiceStageId[] {
  const perms = new Set(permissions);
  if (role === "Admin") return ["intake", "l1", "onsite", "l2", "warehouse", "accounts", "l3", "closed"];
  if (role === "L1 Engineer" || role === "L1 Backup Engineer") {
    return ["intake", "l1", "onsite", "closed"];
  }
  if (role === "L2 Technical Team") {
    return ["intake", "l1", "onsite", "l2", "closed"];
  }
  if (role === "L3 Advanced OEM Support") {
    return ["intake", "l1", "onsite", "l2", "l3", "closed"];
  }

  const stages: ServiceStageId[] = ["intake"];
  const canConsumer = perms.has("complaints:consumer");
  const canSupplier = perms.has("complaints:supplier");
  const canWarehouse = perms.has("inventory:serials") || perms.has("inventory:products") || perms.has("inventory:bom") || perms.has("inventory:raw-materials") || perms.has("inventory:manufactured") || perms.has("dispatch:manage");
  const canAccounts = perms.has("accounts:manage");
  const canL3 = canSupplier || canConsumer;

  if (canConsumer) stages.push("l1", "onsite");
  if (canWarehouse) stages.push("warehouse");
  if (canAccounts) stages.push("accounts");
  if (canL3) stages.push("l3");
  if (canConsumer || canSupplier || canWarehouse || canAccounts) stages.push("closed");
  return Array.from(new Set(stages));
}

