function normalizeServiceAssignmentRole(role: unknown): ServiceAssignmentRole | "" {
  const value = String(role ?? "").trim();
  if (value === "L1") return "L1 Engineer";
  if (value === "Backup" || value === "L1 Backup") return "L1 Backup Engineer";
  if (value === "L2") return "L2 Technical Team";
  if (value === "L3") return "L3 Advanced OEM Support";
  return SERVICE_ASSIGNMENT_ROLES.find((item) => item === value) ?? "";
}

function serviceRoleShortLabel(role: ServiceAssignmentRole) {
  if (role === "L2 Technical Team") return "L2";
  if (role === "L3 Advanced OEM Support") return "L3";
  if (role === "L1 Backup Engineer") return "L1 Backup";
  return "L1";
}

